import{_ as t,o as i,c as o,ag as a}from"./chunks/framework.D23eTBvy.js";const g=JSON.parse('{"title":"VNNotes Architecture & Technical Documentation","description":"","frontmatter":{},"headers":[],"relativePath":"vnnotes_architecture.md","filePath":"vnnotes_architecture.md"}'),n={name:"vnnotes_architecture.md"};function r(s,e,l,c,d,u){return i(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="vnnotes-architecture-technical-documentation" tabindex="-1">VNNotes Architecture &amp; Technical Documentation <a class="header-anchor" href="#vnnotes-architecture-technical-documentation" aria-label="Permalink to &quot;VNNotes Architecture &amp; Technical Documentation&quot;">​</a></h1><blockquote><p><strong>Executive Summary:</strong> VNNotes is a stealth-oriented, multi-pane note-taking and teleprompter application built using Python and PyQt6. It provides local-first, anti-capture &quot;phantom&quot; functionality designed primarily for meetings and interviews, alongside a tight integrated web-based Plugin Market.</p></blockquote><h2 id="_1-system-architecture-overview" tabindex="-1">1. System Architecture Overview <a class="header-anchor" href="#_1-system-architecture-overview" aria-label="Permalink to &quot;1. System Architecture Overview&quot;">​</a></h2><p>VNNotes utilizes a desktop-first architecture combining native Windows APIs with a robust UI layout engine (<code>QDockWidget</code>). The application logic resides in standard domain-driven hierarchies, bridging Python execution with modern web technologies (<code>QWebEngineView</code>) for complex integrated components (like the Plugin Marketplace and local search engines).</p><h3 id="key-subsystems" tabindex="-1">Key Subsystems: <a class="header-anchor" href="#key-subsystems" aria-label="Permalink to &quot;Key Subsystems:&quot;">​</a></h3><ul><li><strong>Core Engine:</strong> Application lifecycle, threading, environment optimizations (GPU).</li><li><strong>UI &amp; Layout Manager:</strong> Handles the <code>QMainWindow</code>, nested docks, and flexible sidebars using customized <code>DockManager</code> and <code>ThemeManager</code> modules.</li><li><strong>Phantom Layer (Anti-Capture):</strong> Integrates with <code>ctypes.windll.user32.SetWindowDisplayAffinity</code> to make windows invisible to Discord, Zoom, OBS, and Teams.</li><li><strong>Plugin System &amp; Market Bridge:</strong> Supports dynamic Python-based plugins (<code>src.core.plugins.PluginManager</code>) and a <code>QWebChannel</code>-based bridge (<code>MarketBridge</code>) communicating directly with Next.js web applications.</li><li><strong>Infrastructure:</strong> Local-first session and clipboard control without utilizing any cloud sync features to maximize data sovereignty.</li></ul><h2 id="_2-core-components" tabindex="-1">2. Core Components <a class="header-anchor" href="#_2-core-components" aria-label="Permalink to &quot;2. Core Components&quot;">​</a></h2><h3 id="main-py" tabindex="-1"><code>main.py</code> <a class="header-anchor" href="#main-py" aria-label="Permalink to &quot;`main.py`&quot;">​</a></h3><p>The entry point of VNNotes. It enforces critical environment parameters before initiating the Qt loop:</p><ul><li>Allows hardware acceleration (<code>QT_OPENGL=&quot;desktop&quot;</code>) while disabling Chromium logs.</li><li>Instantiates <code>QApplication</code>, configures shared OpenGL contexts, and defines the global exception hook for graceful crash telemetry (<code>FATAL_CRASH.txt</code>).</li></ul><h3 id="mainwindow-src-ui-main-window-py" tabindex="-1"><code>MainWindow</code> (<code>src/ui/main_window.py</code>) <a class="header-anchor" href="#mainwindow-src-ui-main-window-py" aria-label="Permalink to &quot;`MainWindow` (`src/ui/main_window.py`)&quot;">​</a></h3><p>The central nervous system of the UI layout:</p><ul><li><strong><code>DockManager</code></strong>: Orchestrates nested <code>QDockWidget</code> objects. Provides APIs to split notes right/down, preventing native layout crashes through careful bounding.</li><li><strong><code>SidebarWidget</code></strong>: A resizable tree view of the filesystem or local notes database, restricted to the left area.</li><li><strong><code>VisibilityManager</code></strong>: Controls the Anti-Capture toggles and window opacity shortcuts.</li><li><strong><code>MarketBridge</code></strong>: Mounts <code>window.vnnotes_market</code> using <code>QWebChannel</code> for a seamless hybrid React-to-Python application market experience.</li></ul><h2 id="_3-design-decisions-rationale" tabindex="-1">3. Design Decisions &amp; Rationale <a class="header-anchor" href="#_3-design-decisions-rationale" aria-label="Permalink to &quot;3. Design Decisions &amp; Rationale&quot;">​</a></h2><ul><li><strong>PyQt6 over Electron:</strong> PyQt6 allows deeply integrated native Windows API manipulation (essential for the <code>SetWindowDisplayAffinity</code> anti-capture stealth modes) while maintaining low memory footprint compared to Chrome V8 overheads.</li><li><strong>Local-First Zero-Cloud:</strong> Protects the sensitive nature of meeting notes and interviews. No telemetry.</li><li><strong>Hybrid Market Strategy:</strong> While the core app is fast and native, the <em>Plugin Market</em> is built with Next.js to leverage sleek, modern web aesthetics and fast iteration via <code>QWebEngineView</code>. To avoid Electron&#39;s bloat, this is a local/remote bridge strictly limited to market/browser operations.</li></ul><h2 id="_4-integration-points-market-bridge" tabindex="-1">4. Integration Points (Market Bridge) <a class="header-anchor" href="#_4-integration-points-market-bridge" aria-label="Permalink to &quot;4. Integration Points (Market Bridge)&quot;">​</a></h2><p>The market bridge (<code>src/core/market_bridge.py</code>) defines a PyQt slot mechanism exposed via <code>QWebChannel</code>.</p><ol><li>The Next.js frontend calls <code>window.vnnotes_market.install_plugin(id, url)</code>.</li><li>The Python handler downloads the zip, verifies integrity, and unpacks to the <code>plugins/</code> directory.</li><li>The <code>PluginManager</code> dynamically loads the components into the active layout.</li></ol><h2 id="_5-security-privacy-model" tabindex="-1">5. Security &amp; Privacy Model <a class="header-anchor" href="#_5-security-privacy-model" aria-label="Permalink to &quot;5. Security &amp; Privacy Model&quot;">​</a></h2><ul><li><strong>Memory Safety:</strong> Does not access untrusted memory addresses manually. Local Python scope execution only.</li><li><strong>Data Protection:</strong> Files are stored cleanly on disk in a standalone private vault format.</li><li><strong>Plugin Sandboxing:</strong> (Roadmap) Currently, plugins run in the same process space, requiring vetted/trusted plugins for core functionality. Future implementations might utilize separate processes.</li></ul><h2 id="_6-glossary" tabindex="-1">6. Glossary <a class="header-anchor" href="#_6-glossary" aria-label="Permalink to &quot;6. Glossary&quot;">​</a></h2><ul><li><strong>Phantom Mode:</strong> The state where the application window is flagged as <code>WDA_EXCLUDEFROMCAPTURE</code>, disappearing from stream encoders.</li><li><strong>Ultra-Hub:</strong> Embedded browser dock allowing inline lookups.</li><li><strong>Zeta Strategy:</strong> Atomic visibility toggling rules defined in the <code>MainWindow</code> layout refresh cycle to prevent visual stutter.</li></ul>',22)])])}const m=t(n,[["render",r]]);export{g as __pageData,m as default};
